mapper.select:
SELECT s.id, s.dog_id AS dogId, d.name AS dogName, d.profile_image_url AS dogProfileImageUrl, s.title, s.schedule_date AS scheduleDate, s.schedule_type_id AS scheduleTypeId, c.code_name AS scheduleTypeName, s.is_completed AS isCompleted, s.memo, s.location, (SELECT COUNT(*) FROM public.file_mappings fm WHERE fm.target_id = s.id AND fm.target_type_id = (SELECT id FROM public.codes WHERE group_code = 'FILE_TARGET_TYPE' AND code = 'SCHEDULE')) AS attachmentCount FROM public.schedules s JOIN public.dogs d ON s.dog_id = d.id LEFT JOIN public.codes c ON s.schedule_type_id = c.id WHERE d.user_id = #{userId}
AND s.dog_id = #{dogId}
AND s.schedule_type_id = #{typeId}
AND (s.title LIKE '%' || #{keyword} || '%' OR s.memo LIKE '%' || #{keyword} || '%')
AND s.schedule_date >= CAST(#{startDate} AS TIMESTAMP)
AND s.schedule_date <= CAST(#{endDate} || ' 23:59:59' AS TIMESTAMP)
ORDER BY s.schedule_date ASC
